import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import FloatingNode from './FloatingNode';

interface NodeConfig {
  id: string;
  type: 'cube' | 'cross' | 'dot';
  position: { top: string; left: string };
  size: number;
  depth: 'far' | 'mid' | 'near';
  delay: number;
  duration: number;
  color: string;
  parallaxFactor: number; // How much to move with scroll (0-1)
}

const FloatingNodesBackground: React.FC = () => {
  const [scrollY, setScrollY] = useState(0);
  const [offsetY, setOffsetY] = useState(0);

  // Generate node configurations
  const nodes: NodeConfig[] = [
    // Far layer - blurred wireframe cubes
    {
      id: 'cube-1',
      type: 'cube',
      position: { top: '10%', left: '8%' },
      size: 40,
      depth: 'far',
      delay: 0,
      duration: 8,
      color: '#00FF41',
      parallaxFactor: 0.1,
    },
    {
      id: 'cube-2',
      type: 'cube',
      position: { top: '60%', left: '85%' },
      size: 50,
      depth: 'far',
      delay: 2,
      duration: 10,
      color: '#C5A059',
      parallaxFactor: 0.1,
    },
    {
      id: 'cross-1',
      type: 'cross',
      position: { top: '25%', left: '75%' },
      size: 35,
      depth: 'far',
      delay: 1,
      duration: 9,
      color: '#0099FF',
      parallaxFactor: 0.1,
    },
    // Mid layer - semi-visible nodes
    {
      id: 'dot-1',
      type: 'dot',
      position: { top: '15%', left: '20%' },
      size: 6,
      depth: 'mid',
      delay: 0.5,
      duration: 6,
      color: '#00FF41',
      parallaxFactor: 0.3,
    },
    {
      id: 'cross-2',
      type: 'cross',
      position: { top: '50%', left: '15%' },
      size: 30,
      depth: 'mid',
      delay: 1.5,
      duration: 11,
      color: '#C5A059',
      parallaxFactor: 0.3,
    },
    {
      id: 'cube-3',
      type: 'cube',
      position: { top: '70%', left: '45%' },
      size: 35,
      depth: 'mid',
      delay: 0.8,
      duration: 7.5,
      color: '#FF3E3E',
      parallaxFactor: 0.3,
    },
    {
      id: 'dot-2',
      type: 'dot',
      position: { top: '35%', left: '60%' },
      size: 8,
      depth: 'mid',
      delay: 1.2,
      duration: 5,
      color: '#0099FF',
      parallaxFactor: 0.3,
    },
    // Near layer - sharp nodes
    {
      id: 'cross-3',
      type: 'cross',
      position: { top: '20%', left: '40%' },
      size: 45,
      depth: 'near',
      delay: 0.3,
      duration: 8.5,
      color: '#00FF41',
      parallaxFactor: 0.5,
    },
    {
      id: 'dot-3',
      type: 'dot',
      position: { top: '55%', left: '25%' },
      size: 10,
      depth: 'near',
      delay: 2.5,
      duration: 7,
      color: '#C5A059',
      parallaxFactor: 0.5,
    },
    {
      id: 'cube-4',
      type: 'cube',
      position: { top: '65%', left: '70%' },
      size: 55,
      depth: 'near',
      delay: 1.1,
      duration: 9.5,
      color: '#0099FF',
      parallaxFactor: 0.5,
    },
    {
      id: 'dot-4',
      type: 'dot',
      position: { top: '10%', left: '55%' },
      size: 7,
      depth: 'near',
      delay: 0.7,
      duration: 6.5,
      color: '#FF3E3E',
      parallaxFactor: 0.5,
    },
  ];

  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
      // Parallax offset is opposite to scroll (nodes move up when user scrolls down)
      setOffsetY(-window.scrollY * 0.2);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <motion.div
      className="floating-nodes-background fixed inset-0 overflow-hidden pointer-events-none z-0"
      style={{
        y: offsetY,
      }}
    >
      {nodes.map((node) => (
        <FloatingNode
          key={node.id}
          type={node.type}
          position={node.position}
          size={node.size}
          depth={node.depth}
          delay={node.delay}
          duration={node.duration}
          color={node.color}
        />
      ))}
    </motion.div>
  );
};

export default FloatingNodesBackground;
